// ── HELPER: Aleatorizar array ──
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// ── HELPER: Coger N elementos aleatorios ──
function pickRandom(arr, n) {
  return shuffle(arr).slice(0, n);
}

