// FUNCIONES PÚBLICAS — generan exámenes aleatorios
// ══════════════════════════════════════════════════════════════════════

function getExamenOrtografia() {
  const frases = pickRandom(TODAS_FRASES_ORT, 10);
  return frases.map((f, i) => ({ ...f, num: i + 1 }));
}

function getExamenGramatica() {
  const preguntas = pickRandom(TODAS_PREGUNTAS_GRAM, 5);
  return preguntas.map((p, i) => ({ ...p, num: i + 1 }));
}

function getExamenIngles() {
  // Mezclar sin repetir la misma pregunta dos veces
  const preguntas = pickRandom(TODAS_PREGUNTAS_ING, 20);
  // Aleatorizar también el orden de las opciones dentro de cada pregunta
  return preguntas.map((p, i) => {
    const opciones = shuffle(['A','B','C','D']);
    const mapa = {};
    opciones.forEach((orig, idx) => { mapa[orig] = ['A','B','C','D'][idx]; });
    const newP = {
      num: i + 1,
      pregunta: p.pregunta,
      correcta: mapa[p.correcta],
      explicacion: p.explicacion,
      f: p.f,
    };
    ['A','B','C','D'].forEach((lbl, idx) => {
      newP[lbl] = p[opciones[idx]];
    });
    return newP;
  });
}

